/// Default ModelRegistry contract address. Expected to be set at genesis.
///
/// This is the deterministic deployment address in our genesis setup flow.
/// Once the chain is live this can be refactored for permanent use.
///
/// CRITICAL: This MUST match the genesis ModelPricingRegistry address!
/// If this doesn't match, LLM calls will timeout (100+ blocks to mine).
/// See IMAGE-IMPLEMENTATION-PLAN.md Section 16.1 for debugging history.
///
/// Source of truth: ritual-common-internal/src/ritual_common/contract_addresses.py
/// MODEL_PRICING_REGISTRY_CONTRACT_ADDRESS = "0x7A85F48b971ceBb75491b61abe279728F4c4384f"
pub const DEFAULT_MODEL_REGISTRY_ADDRESS: Address =
    address!("7A85F48b971ceBb75491b61abe279728F4c4384f");

// ============================================================================
// ZK TWO-PHASE (0x0806) CONSTANTS
// ============================================================================

/// Per-iteration fee for Sovereign Agent operations.
/// Each iteration involves LLM inference in the Sovereign Agent.
///
/// **Calibration target:** one sovereign agent at `frequency=1000`, `iter=10`, `tools=10`
/// should consume ~1 RIT per day on a 300ms-block chain (288 fires per day, ~3,461 µRIT
/// per fire including Phase 1 overhead). Holding the historical 2:1 TOOL:ITER ratio:
///   per fire ≈ 10·ITER + 10·TOOL = 30·ITER ≈ 3.45 mRIT  →  ITER ≈ 115 µRIT
/// Previous value (0.00000025 ETH) gave ~200 days/RIT at the same workload.
pub const SOVEREIGN_AGENT_ITERATION_FEE_WEI: u128 = 115_000_000_000_000; // 0.000115 ETH

/// Per-tool-call fee for Sovereign Agent operations.
/// Each tool call involves file read/write/execute.
///
/// Calibrated as 2× `SOVEREIGN_AGENT_ITERATION_FEE_WEI` per the historical ratio.
/// See ITERATION_FEE doc-comment for the per-day-per-RIT derivation.
pub const SOVEREIGN_AGENT_TOOL_CALL_FEE_WEI: u128 = 230_000_000_000_000; // 0.000230 ETH

/// Maximum iterations allowed for Sovereign Agent calls (for escrow calculation)
pub const SOVEREIGN_AGENT_MAX_ITERATIONS: u32 = 50;

